package main;

public class ConditionalStatement {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		int a=10;
		int b=23;
		int res=a>b?10:20;
		if (a==b) {
			System.out.println("Hello");
		}else {
			System.out.println("Bye");
		}
		System.out.println(res);

	}

}
